@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonText { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSend { get; set; }

    private string text = "";

    private async Task Send()
    {
        if (string.IsNullOrWhiteSpace(text)) return;
        var content = text.Trim();
        text = "";
        await OnSend.InvokeAsync(content);
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await Send();
        }
    }
}
"}

{"path": "/tmp/sv-2bdedebfd1c743d293d40ceabbcb5bb9/Components/Chat/MessageItem.razor", "file_text": "<div class="message-item p-2 rounded position-relative"
     @onmouseenter="() => isHovered = true"
     @onmouseleave="OnMouseLeave">

    <div class="d-flex justify-content-between align-items-start">
        <div>
            <strong>@Message.Author</strong>
            <small class="text-muted ms-2">@FormatRelativeTime(Message.SentAt)</small>
        </div>
        @if (isHovered)
        {
            <div class="d-flex gap-1">
                <button class="btn btn-sm btn-outline-secondary py-0 px-1"
                        title="React"
                        @onclick="() => showEmojiPicker = !showEmojiPicker">
                    😀
                </button>
                <button class="btn btn-sm btn-outline-secondary py-0 px-1"
                        title="Reply in thread"
                        @onclick="HandleOpenThread">
                    💬
                </button>
            </div>
        }
    </div>

    <p class="mb-1 mt-1">@Message.Content</p>

    @if (showEmojiPicker)
    {
        <div class="d-flex gap-1 mb-1">
            @foreach (var emoji in CommonEmojis)
            {
                <button class="btn btn-sm btn-outline-secondary py-0 px-1"
                        @onclick="() => HandleReact(emoji)">
                    @emoji
                </button>
            }
        </div>
    }

    @if (Message.Reactions?.Count > 0)
    {
        <div class="d-flex gap-1 flex-wrap mb-1">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="badge bg-light text-dark border reaction-badge"
                      title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (ThreadSummary is not null)
    {
        <a href="javascript:void(0)" class="thread-link small" @onclick="HandleOpenThread">
            @ThreadSummary.ReplyCount replies
        </a>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public ThreadSummary? ThreadSummary { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool isHovered;
    private bool showEmojiPicker;

    private static readonly string[] CommonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private void OnMouseLeave()
    {
        isHovered = false;
        showEmojiPicker = false;
    }

    private async Task HandleOpenThread()
    {
        await OnOpenThread.InvokeAsync(Message.Id);
    }

    private async Task HandleReact(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}
"}

