        messages = await ChatService.GetMessagesAsync(selectedChannelId, 0, messages.Count);
    }

    private static Dictionary<int, ThreadSummary> BuildThreadSummaries(List<Message> msgs)
    {
        return msgs
            .Where(m => m.ReplyToId.HasValue)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(
                g => g.Key,
                g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)));
